describe("Global Base Config", () => {
  let globalBaseConfig;
  beforeEach(() => {
    jest.resetModules();
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    globalBaseConfig = require("config/global-base-config").globalBaseConfig;
  });
  describe("sealandMaerskRegionSelected: in BRANDS", () => {
    it("takes the value of the default regionSelected, if no regionSelected cookie set", () => {
      const sealandmaerskBrandConfig = globalBaseConfig.BRANDS.find((brand) => brand.brandName === "sealandmaersk");
      expect(sealandmaerskBrandConfig.brandCode).toBe(globalBaseConfig.DEFAULT_SEALANDMAERSK_REGION_CODE);
    });
    it("uses the default region code if the cookie is invalid", () => {
      document.cookie = `regionSelected=maeu`;
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      globalBaseConfig = require("config/global-base-config").globalBaseConfig;
      const sealandmaerskBrandConfig = globalBaseConfig.BRANDS.find((brand) => brand.brandName === "sealandmaersk");
      expect(sealandmaerskBrandConfig.brandCode).toBe(globalBaseConfig.DEFAULT_SEALANDMAERSK_REGION_CODE);
    });
  });
  describe("sealandMaerskRegionSelected: in AO.brandCodeUrlMapping", () => {
    it("takes the value of the default regionSelected, if no regionSelected cookie set", () => {
      const sealandmaerskBrandConfig = globalBaseConfig.AO.brandCodeUrlMapping.sealandmaersk;
      expect(sealandmaerskBrandConfig).toBe(globalBaseConfig.DEFAULT_SEALANDMAERSK_REGION_CODE);
    });
  });
  describe("Design Name - provides a design system brand code", () => {
    test.each`
      brandCode | designCode
      ${"maeu"} | ${"maeu"}
      ${"sejj"} | ${"seau"}
      ${"mcpu"} | ${"seau"}
      ${"seau"} | ${"seau"}
      ${"maei"} | ${"maeu"}
      ${"sudu"} | ${"hsud"}
      ${"anrm"} | ${"anrm"}
    `("returns the right design code for each brand code - $brandCode -> $designCode", ({ brandCode, designCode }) => {
      const brand = globalBaseConfig.BRANDS.find((config) => config.brandCode === brandCode);
      expect(brand.designCode).toBe(designCode);
    });
  });

  describe("Language code - provides a brand code specific for SC9 translations", () => {
    test.each`
      brandCode | langCode
      ${"maeu"} | ${"maeu"}
      ${"sejj"} | ${"seau"}
      ${"mcpu"} | ${"seau"}
      ${"seau"} | ${"seau"}
      ${"maei"} | ${"maei"}
      ${"sudu"} | ${"hsud"}
      ${"anrm"} | ${"anrm"}
    `("returns the right design code for each brand code - $brandCode -> $langCode", ({ brandCode, langCode }) => {
      const brand = globalBaseConfig.BRANDS.find((config) => config.brandCode === brandCode);
      expect(brand.langCode).toBe(langCode);
    });
  });

  describe("Scac code - provides a carrier code", () => {
    test.each`
      brandCode | scacCode
      ${"maeu"} | ${"maeu"}
      ${"sejj"} | ${"sejj"}
      ${"mcpu"} | ${"mcpu"}
      ${"seau"} | ${"seau"}
      ${"maei"} | ${"maei"}
      ${"sudu"} | ${"sudu"}
      ${"anrm"} | ${"anrm"}
    `("returns the right scac code for each brand code - $brandCode -> $scacCode", ({ brandCode, scacCode }) => {
      const brand = globalBaseConfig.BRANDS.find((config) => config.brandCode === brandCode);
      expect(brand.scacCode).toBe(scacCode);
    });
  });

  describe("SSR: if there's no document, the code fails gracefully", () => {
    let d = global.document;
    delete global.document;
    try {
      globalBaseConfig = require("config/global-base-config").globalBaseConfig;
      expect(globalBaseConfig).toBeDefined();
    } catch (e) {
      console.log(e);
    }
    global.document = d;
  });
});
